1	#!/usr/bin/env node
2	
3	/**
4	 * 小满CRM — 全流程自动化
5	 *
6	 * 用法: node run-scrape.mjs
7	 * 前置条件:
8	 *   1. Chrome 已在端口 9222 开启 (node launch_okki2.js)
9	 *   2. 小满已登录并在 TM 消息页面
10	 */
11	
12	import { chromium } from 'playwright';
13	import { writeFileSync, mkdirSync, existsSync } from 'fs';
14	import { join, dirname } from 'path';
15	import { fileURLToPath } from 'url';
16	import { classifyAll, getCategoryInfo } from './classifier.mjs';
17	import { generateReportDocx } from './reporter.mjs';
18	import { saveCustomerImages, extractFileUrls } from './image-utils.mjs';
19	import { Packer } from 'docx';
20	
21	const __dirname = dirname(fileURLToPath(import.meta.url));
22	const DATA_DIR = join(__dirname, '..');
23	const CDP_URL = 'http://127.0.0.1:9222';
24	
25	// ============================================================
26	// 连接小满
27	// ============================================================
28	async function connect() {
29	  const browser = await chromium.connectOverCDP(CDP_URL);
30	  const ctx = browser.contexts()[0];
31	  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
32	  if (!page) throw new Error('未找到小满页面');
33	  const talkFrame = page.frames()[1];
34	  if (!talkFrame) throw new Error('未找到聊天 iframe');
35	  return { browser, ctx, page, talkFrame };
36	}
37	
38	// ============================================================
39	// 提取会话列表
40	// ============================================================
41	async function getConversationList(frame) {
42	  return frame.evaluate(() => {
43	    return Array.from(document.querySelectorAll('.contact-item-container')).map(el => {
44	      const text = el.textContent || '';
45	      const nameEl = el.querySelector('.contact-right');
46	      const nameText = nameEl ? (nameEl.textContent || '').trim() : '';
47	      const nameMatch = nameText.match(/^(.+?)(?:\d{2,4}[-:\/])/);
48	      const name = nameMatch ? nameMatch[1].trim() : nameText.substring(0, 30).trim() || 'unknown';
49	      return {
50	        name,
51	        isUnread: text.includes('[未读]'),
52	        isSelected: el.classList.contains('selected'),
53	      };
54	    });
55	  });
56	}
57	
58	// ============================================================
59	// 提取当前会话消息
60	// ============================================================
61	async function getCurrentMessages(frame) {
62	  return frame.evaluate(() => {
63	    const messages = [];
64	    document.querySelectorAll('.message-item-wrapper.messenger').forEach(wrapper => {
65	      const isLeft = wrapper.classList.contains('item-left');
66	      const isRight = wrapper.classList.contains('item-right');
67	      const textEl = wrapper.querySelector('.session-rich-content.text');
68	      const cardEl = wrapper.querySelector('.session-rich-content.card');
69	      const securityEl = wrapper.querySelector('.session-security');
70	
71	      if (!textEl && !cardEl) return;
72	      if (securityEl) return;
73	
74	      const content = (textEl || cardEl).textContent.trim()
75	        .replace(/翻译中…反馈$/, '').replace(/由阿里翻译提供反馈$/, '')
76	        .replace(/阿里国际Marco大模型翻译反馈$/, '').replace(/由阿里翻译提供$/, '').trim();
77	
78	      messages.push({
79	        side: isLeft ? 'received' : isRight ? 'sent' : 'system',
80	        content,
81	        isCard: !!cardEl,
82	      });
83	    });
84	    return messages;
85	  });
86	}
87	
88	// ============================================================
89	// 点击会话
90	// ============================================================
91	async function clickConversation(frame, index) {
92	  const result = await frame.evaluate((idx) => {
93	    const containers = document.querySelectorAll('.contact-item-container');
94	    const target = containers[idx];
95	    if (!target) return null;
96	    target.scrollIntoView({ block: 'center' });
97	    target.click();
98	    return (target.textContent || '').trim().substring(0, 150);
99	  }, index);
100	  await new Promise(r => setTimeout(r, 2000));
101	  return result;
102	}
103	
104	// ============================================================
105	// 提取单个会话详细消息（含重试）
106	// ============================================================
107	async function extractConversation(frame, conv, index) {
108	  const clicked = await clickConversation(frame, index);
109	  if (!clicked) return null;
110	
111	  // Wait for messages to load
112	  for (let i = 0; i < 15; i++) {
113	    const hasContent = await frame.evaluate(() =>
114	      document.querySelectorAll('.session-rich-content.text, .session-rich-content.card').length > 0
115	    );
116	    if (hasContent) break;
117	    await new Promise(r => setTimeout(r, 500));
118	  }
119	
120	  const messages = await getCurrentMessages(frame);
121	  return {
122	    name: conv.name,
123	    status: conv.isUnread ? 'unread' : 'read',
124	    messages,
125	    messageCount: messages.length,
126	  };
127	}
128	
129	// ============================================================
130	// 滚动会话列表
131	// ============================================================
132	async function scrollToBottom(frame) {
133	  await frame.evaluate(() => {
134	    const container = document.querySelector('.seller-conversation-list') ||
135	      document.querySelector('.conversation-list-content');
136	    if (container) container.scrollTop = container.scrollHeight;
137	  });
138	  await new Promise(r => setTimeout(r, 500));
139	}
140	
141	// ============================================================
142	// 主流程
143	// ============================================================
144	async function main() {
145	  console.log('╔══════════════════════════════════════╗');
146	  console.log('║   小满CRM 客户跟进管理系统            ║');
147	  console.log('║   数据抓取 → 分类 → 报告              ║');
148	  console.log('╚══════════════════════════════════════╝\n');
149	
150	  // Step 1: 连接
151	  console.log('📡 连接小满...');
152	  const { browser, ctx, talkFrame } = await connect();
153	  console.log('✅ 连接成功\n');
154	
155	  try {
156	    // Step 2: 获取会话列表
157	    console.log('📋 获取会话列表...');
158	    await scrollToBottom(talkFrame);
159	    await scrollToBottom(talkFrame);
160	    const conversations = await getConversationList(talkFrame);
161	    console.log(`   共 ${conversations.length} 个会话\n`);
162	
163	    // Step 3: 提取详细消息（遍历前25个）
164	    const maxConv = conversations.length;
165	    const detailedConvs = [];
166	    const imageDedup = new Set();
167	    const startTime = Date.now();
168	
169	    for (let i = 0; i < maxConv; i++) {
170	      const conv = conversations[i];
171	      if (conv.name === 'Assistant Eva官方') continue;
172	
173	      process.stdout.write(`   [${i + 1}/${maxConv}] ${conv.name}...`);
174	
175	      const detail = await extractConversation(talkFrame, conv, i);
176	      if (detail) {
177	        // 保存该客户的图片
178	        const savedImages = await saveCustomerImages(ctx, talkFrame, conv.name, imageDedup);
179	        if (savedImages.length > 0) {
180	          detail.images = savedImages;
181	          process.stdout.write(`📷${savedImages.length} `);
182	        }
183	        // 提取文件链接
184	        const fileUrls = await extractFileUrls(talkFrame);
185	        if (fileUrls.length > 0) {
186	          detail.files = fileUrls;
187	          process.stdout.write(`📎${fileUrls.length} `);
188	        }
189	        detailedConvs.push(detail);
190	        process.stdout.write(` ${detail.messages.length} 条消息 ✅\n`);
191	      } else {
192	        process.stdout.write(' ⚠️ 跳过\n');
193	      }
194	    }
195	
196	    const totalMsg = detailedConvs.reduce((sum, c) => sum + c.messages.length, 0);
197	    const totalImg = detailedConvs.reduce((sum, c) => sum + (c.images?.length || 0), 0);
198	    const totalFiles = detailedConvs.reduce((sum, c) => sum + (c.files?.length || 0), 0);
199	    const elapsed = ((Date.now() - startTime) / 1000).toFixed(0);
200	    console.log(`\n   抓取完成: ${detailedConvs.length} 个会话，${totalMsg} 条消息，${totalImg} 张图片，${totalFiles} 个文件，耗时 ${elapsed}s\n`);
201	
202	    // Step 4: 分类
203	    console.log('🏷️  分类...');
204	    const classified = classifyAll(detailedConvs);
205	
206	    // 统计各分类
207	    const stats = {};
208	    for (const conv of classified) {
209	      const catId = conv.classification?.categoryId || 'other';
210	      stats[catId] = (stats[catId] || 0) + 1;
211	    }
212	    for (const [catId, count] of Object.entries(stats).sort()) {
213	      const info = getCategoryInfo(catId);
214	      if (info) {
215	        console.log(`   ${info.emoji} ${info.label}: ${count} 个`);
216	      }
217	    }
218	    console.log('');
219	
220	    // Step 5: 生成 Word 报告
