203	    ];
204	    for (const sel of selectors) {
205	      const el = document.querySelector(sel);
206	      if (el && el.scrollHeight > el.clientHeight) {
207	        return { selector: sel, scrollHeight: el.scrollHeight, clientHeight: el.clientHeight };
208	      }
209	    }
210	    // Fallback: find any scrollable element containing messages
211	    const wrappers = document.querySelectorAll('.message-item-wrapper.messenger');
