231	  let prevCount = 0;
232	  let stableCount = 0;
233	  let totalScrolled = 0;
234	
235	  for (let i = 0; i < maxScrolls; i++) {
236	    const { count, scrolled } = await frame.evaluate(({ selector, containerInfo: ci }) => {
237	      // Find scroll container
238	      let container = null;
239	      if (selector) {
240	        container = document.querySelector(selector);
241	      } else {
242	        const wrappers = document.querySelectorAll('.message-item-wrapper.messenger');
243	        if (wrappers.length > 0) {
244	          let el = wrappers[0].parentElement;
245	          while (el) {
246	            if (el.scrollHeight > el.clientHeight) { container = el; break; }
247	            el = el.parentElement;
248	          }
249	        }
250	      }
251	      if (!container) return { count: 0, scrolled: false };
