245	    if (hasKeywords(recentContent, [...KEYWORDS.followup_greeting, ...KEYWORDS.inquiry])) {
246	      reasons.push('含跟进/问候内容');
247	      return { categoryId: 'followup', tier: 'B', confidence: 0.7, reasons };
248	    }
249	    return { categoryId: 'followup', tier: 'C', confidence: 0.55, reasons };
250	  }
251	
252	  // 规则 8: 默认
253	  if (totalMsgCount > 10) {
254	    reasons.push('历史互动较多');
255	    return { categoryId: 'keep_warm', tier: 'C', confidence: 0.4, reasons };
256	  }
257	
258	  return { categoryId: 'activate', tier: 'C', confidence: 0.3, reasons };
259	}
260	
261	/**
262	 * 批量分类
263	 */
264	export function classifyAll(conversations) {
265	  return conversations.map(conv => ({
266	    ...conv,
267	    classification: classifyConversation(conv),
268	  }));
269	}
270	
271	/**
272	 * 获取分类详情
273	 */
274	export function getCategoryInfo(categoryId) {
275	  return CATEGORIES.find(c => c.id === categoryId);
276	}
277	
278	/**
279	 * 按分类统计
280	 */
281	export function categorizeSummary(classifiedConversations) {
282	  const summary = {};
283	  for (const cat of CATEGORIES) {
284	    summary[cat.id] = { ...cat, conversations: [], count: 0 };
285	  }
286	
287	  // 未匹配的归入其他
288	  summary.other = { id: 'other', label: '其他', emoji: '❓', priority: 'P4', conversations: [], count: 0 };
289	
290	  for (const conv of classifiedConversations) {
291	    const catId = conv.classification?.categoryId || 'other';
292	    if (summary[catId]) {
293	      summary[catId].conversations.push(conv);
294	      summary[catId].count++;
295	    } else {
296	      summary.other.conversations.push(conv);
297	      summary.other.count++;
298	    }
299	  }
300	
301	  // 按优先级排序
302	  const priority = { 'P0': 0, 'P1': 1, 'P2': 2, 'P3': 3, 'P4': 4 };
303	  return Object.values(summary)
304	    .filter(c => c.count > 0)
305	    .sort((a, b) => (priority[a.priority] || 99) - (priority[b.priority] || 99));
306	}
