/**
 * TM页面结构诊断 — 找出数据存储方式和正确的抓取策略
 * 用法: node diagnose-tm.mjs
 */

import { chromium } from 'playwright';

const CDP_URL = 'http://127.0.0.1:9222';

async function connect() {
  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  if (!page) throw new Error('未找到小满页面');
  const talkFrame = page.frames()[1];
  if (!talkFrame) throw new Error('未找到聊天 iframe');
  return { browser, ctx, page, talkFrame };
}

async function main() {
  const { talkFrame } = await connect();
  console.log('=== TM页面诊断 ===\n');

  // 1. 检查有多少个frame
  const frames = talkFrame.childFrames();
  console.log('子frame数:', frames.length);

  // 2. 找到对话列表的容器和数据结构
  const diag = await talkFrame.evaluate(() => {
    const info = {};

    // 查找滚动容器
    const containers = [];
    document.querySelectorAll('*').forEach(el => {
      if (el.scrollHeight > el.clientHeight + 10 && el.clientHeight > 100) {
        containers.push({
          tag: el.tagName,
          id: el.id || '',
          className: (el.className?.toString() || '').substring(0, 80),
          scrollHeight: el.scrollHeight,
          clientHeight: el.clientHeight,
          childCount: el.children.length,
        });
      }
    });
    info.scrollContainers = containers.slice(0, 10);

    // 查找 contact-item-container
    const contactItems = document.querySelectorAll('.contact-item-container');
    info.contactItemCount = contactItems.length;

    // 查找可能的列表数据
    const listEl = document.querySelector('.seller-conversation-list') ||
      document.querySelector('.conversation-list-content') ||
      document.querySelector('.im-conversation-list-container');

    if (listEl) {
      info.listContainerTag = listEl.tagName;
      info.listContainerClass = (listEl.className?.toString() || '').substring(0, 100);
      info.listContainerScrollH = listEl.scrollHeight;
