          scrapedAt: new Date().toISOString(),
        });

        successCount++;
        console.log(` ✅ ${messages.length}条`);
      } catch (e) {
        console.log(` ❌ ${e.message.substring(0, 50)}`);
      }

      // 重新获取会话列表（索引可能因点击而变化）
      if ((i + 1) % 10 === 0) {
        const refreshed = await getConversationList(talkFrame);
        refreshed.forEach(c => { nameToIndex[c.name] = c.index; });
      }
    }

    // 保存
    const now = new Date();
    const dateStr = now.toISOString().replace(/[:.]/g, '-').substring(0, 19);
    const outputPath = join(DATA_DIR, `deep_scrape_${dateStr}.json`);

    writeFileSync(outputPath, JSON.stringify({
      scrapedAt: now.toISOString(),
      totalTargeted: toScrape.length,
      successCount,
      skippedCount: skipped.length,
      skipped,
      results,
    }, null, 2));

    console.log(`\n✅ 深抓完成: ${successCount}/${toScrape.length} 成功, ${skipped.length} 跳过`);
    console.log(`   已保存: ${outputPath}`);
  } finally {
    // Don't close browser - it's shared
  }
}

main().catch(err => {
  console.error('[deep-scrape] 错误:', err.message);
  process.exit(1);
});

