// ============ P0分析数据 ============
function getP0Analyses(p0Customers, deepMap) {
  const analyses = [];

  for (const c of p0Customers) {
    const deep = deepMap[c.name];
    const daysAgo = Math.round((Date.now() - (c.lastContactTime || c.modifyTime || 0)) / 86400000);
    const msg = c.latestMessageContent || c.domLastMsg || '';
    const country = c.countryCode || '?';

    const analysis = {
      name: c.name,
      country,
      isUnread: c.isUnread,
      step1: [
        `国家/区域: ${getCountryName(country)} (${country})`,
        `买家等级: ${c.buyerLevel || '未知'}`,
        `最近互动: ${daysAgo}天前`,
        `沟通语言: ${detectLanguage(msg)}`,
      ],
      step2: [],
      step3: [],
      step4: '',
      step4Lines: [],
      step5: [],
    };

    // 根据对话内容生成分析
    const content = msg.toLowerCase();
    const hasPrice = /price|cost|how much|报价|价格/i.test(content);
    const hasShipping = /ship|delivery|shipping|dhl|fedex|海运/i.test(content);
    const hasSample = /sample|样品/i.test(content);
    const hasPayment = /payment|pay|deposit/i.test(content);
    const hasComplaint = /complaint|return|refund|damage|quality issue/i.test(content);
    const isArabic = /[؀-ۿ]/.test(msg);
    const isFrench = /[àâçéèêëîïôûùüÿœæ]/i.test(msg);
    const isSpanish = /[áéíóúñ¿¡]/i.test(msg);
    const isRussian = /[А-Яа-я]/.test(msg);

    if (c.isUnread && daysAgo <= 1 && hasPrice) {
      analysis.step2 = ['客户刚询价，等待报价回复', '时间窗口紧，延迟回复可能导致客户流失'];
      analysis.step3 = [
        { label: '策略', planA: '发标准报价模板', planB: '报价 + 差异化价值点 + 低门槛钩子' },
        { label: '优势', planA: '快速，省事', planB: '客户同时收到价格和品质证据，难以直接比价' },
        { label: '风险', planA: '客户拿去比价，一场空', planB: '需要准备对应素材（面料图/证书）' },
        { label: '适用', planA: '非核心客户', planB: '所有P0客户（推荐）' },
      ];
      analysis.step4 = `关于您询问的${isArabic ? 'المنتج' : '产品'}，报价如下——同时附上我们工厂的核心优势供您参考。`;
      analysis.step4Lines = [
        `单价预估: $X.XX/pc（最终价格老板确认）`,
        `工厂: 帮宝适2024奥运联名款指定生产商，6000㎡自有工厂`,
        `品质: 预洗精梳棉——你收到后洗烘两次，尺寸不变，手感不变`,
        `[钩子] 我刚好有两片面料对比图——普通棉 vs 我们用的预洗精梳棉，10秒你就看得出差别。发你看看？`,
      ];
      analysis.step5 = [
        '✅ 客户回复感兴趣 → 发面料对比图 + 确认数量和地址 → 出正式PI',
        '⚠️ 客户说价格贵 → "这个量我可以帮您争取更优价，您预算多少？"',
        '⏰ 客户3天不回 → 用帮宝适奥运背书钩子重新激活',
      ];
    } else if (c.isUnread && daysAgo > 7) {
