  for (let i = 0; i < skippedP0P1.length; i++) {
    const target = skippedP0P1[i];
    const idx = nameToIdx[target.name];

    if (idx === undefined) {
      console.log(`[${i+1}/${skippedP0P1.length}] ⚠️ ${target.name} - 不在DOM`);
      continue;
    }

    process.stdout.write(`[${i+1}/${skippedP0P1.length}] ${target.priority} ${target.name}...`);
    try {
      await clickConversation(talkFrame, idx);
      const has = await waitForMessages(talkFrame);
      if (!has) { console.log(' 无消息'); continue; }

      const cnt = await scrollChatToLoadAll(talkFrame);
      const msgs = await getMessages(talkFrame);
      results.push({
        name: target.name,
        priority: target.priority,
        tier: target.tier,
        countryCode: target.countryCode,
        reasons: target.reasons,
        messageCount: msgs.length,
        messages: msgs,
      });
      console.log(` ✅ ${msgs.length}条`);
    } catch (e) {
      console.log(` ❌ ${e.message?.substring(0, 50)}`);
    }
  }

  // 合并到之前的结果
  const merged = {
    ...prev,
    scrapedAt: new Date().toISOString(),
    successCount: prev.successCount + results.length,
    skippedCount: skipped.length - results.length,
    skipped: skipped.filter(s => !results.find(r => r.name === s)),
    results: [...(prev.results || []), ...results],
  };

  const outPath = join(DATA_DIR, `deep_scrape_merged_${new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19)}.json`);
  writeFileSync(outPath, JSON.stringify(merged, null, 2));
  console.log(`\n✅ 合并完成: ${results.length}人新增, 总计${merged.successCount}人 → ${outPath}`);
}

main().catch(err => { console.error(err.message); process.exit(1); });

