/**
 * 分段深抓 — 先抓置顶区域，再滚到普通会话区域，逐个抓取所有P0/P1
 * 用法: node deep-scrape-all-sections.mjs
 */

import { chromium } from 'playwright';
import { writeFileSync, readFileSync, readdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..', 'data');
const CDP_URL = 'http://127.0.0.1:9222';

async function connect() {
  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  const talkFrame = page.frames()[1];
  return { browser, ctx, page, talkFrame };
}

async function getDOMCustomers(frame) {
  return frame.evaluate(() => {
    return Array.from(document.querySelectorAll('.contact-item-container')).map((el, idx) => {
      const nameEl = el.querySelector('.contact-right');
      const nameText = nameEl ? (nameEl.textContent || '').trim() : '';
      const nameMatch = nameText.match(/^(.+?)(?:\d{2,4}[-:\/])/);
      const name = nameMatch ? nameMatch[1].trim() : nameText.substring(0, 30).trim() || 'unknown';
      return { index: idx, name };
    });
  });
}

async function clickAndScrape(frame, index, name) {
  await frame.evaluate((idx) => {
    const containers = document.querySelectorAll('.contact-item-container');
    if (containers[idx]) {
      containers[idx].scrollIntoView({ block: 'center' });
      containers[idx].click();
    }
  }, index);
  await new Promise(r => setTimeout(r, 1500));

  // Wait for messages
  let has = false;
  for (let i = 0; i < 15; i++) {
    has = await frame.evaluate(() =>
      document.querySelectorAll('.session-rich-content.text, .session-rich-content.card').length > 0
    );
    if (has) break;
    await new Promise(r => setTimeout(r, 500));
  }
  if (!has) return null;

  // Scroll to load history
  const info = await frame.evaluate(() => {
    const sels = ['.message-list-container', '.chat-list', '.im-chat-list', '.message-list',
      '[class*="message-list"]', '[class*="chat-list"]', '.session-message-list-wrapper'];
    for (const sel of sels) {
      const el = document.querySelector(sel);
      if (el && el.scrollHeight > el.clientHeight) return { selector: sel };
    }
    return null;
  });

  if (info) {
    let prev = 0, stable = 0;
    for (let i = 0; i < 30; i++) {
      await frame.evaluate((sel) => {
        const el = document.querySelector(sel);
        if (el) el.scrollTop = 0;
      }, info.selector);
      await new Promise(r => setTimeout(r, 500));
      const cnt = await frame.evaluate(() =>
        document.querySelectorAll('.message-item-wrapper.messenger').length
      );
      if (cnt === prev) { stable++; if (stable >= 3) break; }
      else { stable = 0; prev = cnt; }
    }
  }

  // Get messages
  const messages = await frame.evaluate(() => {
    const msgs = [];
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(w => {
      const securityEl = w.querySelector('.session-security');
      if (securityEl) return;
      const textEl = w.querySelector('.session-rich-content.text');
      const cardEl = w.querySelector('.session-rich-content.card');
      let content = '';
      let isCard = false;
      if (textEl) content = textEl.textContent.trim()
        .replace(/翻译中…反馈$/, '').replace(/由阿里翻译提供反馈$/, '')
        .replace(/阿里国际Marco大模型翻译反馈$/, '').replace(/由阿里翻译提供$/, '').trim();
      else if (cardEl) { content = cardEl.textContent.trim(); isCard = true; }
      else return;
      const timeEl = w.querySelector('p.item-base-info span:last-child');
      msgs.push({
        side: w.classList.contains('item-left') ? 'received' : 'sent',
        content: content.substring(0, 2000),
        timestamp: timeEl ? (timeEl.textContent || '').trim() : null,
        isCard,
      });
    });
    return msgs;
  });

  return { name, messageCount: messages.length, messages };
}

async function scrollConversationList(frame, direction = 'down', px = 500) {
  await frame.evaluate(({ dir, p }) => {
    const container = document.querySelector('.seller-conversation-list') ||
      document.querySelector('.conversation-list-content') ||
      document.querySelector('.im-conversation-list-container');
    if (container) {
      container.scrollTop += (dir === 'down' ? p : -p);
    }
  }, { dir: direction, p: px });
  await new Promise(r => setTimeout(r, 300));
}

async function main() {
  // Load P0/P1 target list
  const listFiles = readdirSync(DATA_DIR).filter(f => f.includes('P0P1深抓清单'));
  const p0p1 = JSON.parse(readFileSync(join(DATA_DIR, listFiles.sort().reverse()[0]), 'utf8'));
  const targetNames = new Set(p0p1.map(c => c.name));

  // Load existing deep scrape results
  const deepFiles = readdirSync(DATA_DIR).filter(f => f.startsWith('deep_scrape_merged_') || f.startsWith('deep_scrape_20'));
  let existing = [];
  if (deepFiles.length > 0) {
    const prev = JSON.parse(readFileSync(join(DATA_DIR, deepFiles.sort().reverse()[0]), 'utf8'));
    existing = (prev.results || []).map(r => r.name);
  }

  const toScrape = p0p1.filter(c => !existing.includes(c.name));
  console.log(`P0/P1总计: ${p0p1.length} | 已抓: ${existing.length} | 待抓: ${toScrape.length}\n`);

  if (toScrape.length === 0) {
    console.log('全部已抓完！');
    return;
  }

  const { browser, talkFrame } = await connect();

  // Phase 1: 先抓当前DOM可见的
  const dom1 = await getDOMCustomers(talkFrame);
  console.log(`当前DOM可见: ${dom1.length}个会话`);

  const results = [];
  const remaining = new Set(toScrape.map(c => c.name));

  // 优先抓P0
  const p0ToScrape = toScrape.filter(c => c.priority === 'P0');
  const p1ToScrape = toScrape.filter(c => c.priority === 'P1');
  const ordered = [...p0ToScrape, ...p1ToScrape];

  for (let round = 0; round < 5 && remaining.size > 0; round++) {
    const dom = await getDOMCustomers(talkFrame);
    const nameToIdx = {};
    dom.forEach(c => { nameToIdx[c.name] = c.index; });

    let found = 0;
    for (const target of ordered) {
      if (!remaining.has(target.name)) continue;
      const idx = nameToIdx[target.name];
      if (idx === undefined) continue;

      found++;
      process.stdout.write(`[${results.length + 1}/${toScrape.length}] ${target.priority} ${target.name}...`);
      try {
        const result = await clickAndScrape(talkFrame, idx, target.name);
        if (result) {
          results.push({
            ...result,
            priority: target.priority,
            tier: target.tier,
            countryCode: target.countryCode,
            reasons: target.reasons,
          });
          remaining.delete(target.name);
          console.log(` ✅ ${result.messageCount}条`);
        } else {
          console.log(' ⚠️ 无消息');
        }
      } catch (e) {
        console.log(` ❌ ${e.message?.substring(0, 50)}`);
      }
    }

    if (found === 0 && remaining.size > 0) {
      // 没找到目标——需要滚动列表露出更多会话
      console.log(`\n  当前DOM无目标客户，滚动列表...`);
      // 先滚到底部
      await scrollConversationList(talkFrame, 'down', 2000);
      await new Promise(r => setTimeout(r, 500));
      // 再往上滚一点
      await scrollConversationList(talkFrame, 'up', 800);
      await new Promise(r => setTimeout(r, 300));
    }
  }

  // Merge and save
  const allPrev = deepFiles.length > 0
    ? JSON.parse(readFileSync(join(DATA_DIR, deepFiles.sort().reverse()[0]), 'utf8'))
    : { results: [], skipped: [], successCount: 0 };

  const merged = {
    scrapedAt: new Date().toISOString(),
    successCount: allPrev.successCount + results.length,
    skippedCount: remaining.size,
    skipped: [...remaining],
    results: [...(allPrev.results || []), ...results],
  };

  const dateStr = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
  const outPath = join(DATA_DIR, `deep_scrape_final_${dateStr}.json`);
  writeFileSync(outPath, JSON.stringify(merged, null, 2));

  console.log(`\n✅ 本轮新增: ${results.length} | 仍缺失: ${remaining.size}`);
  console.log(`   总计: ${merged.successCount}人 → ${outPath}`);
  if (remaining.size > 0) console.log(`   仍缺失: ${[...remaining].join(', ')}`);
}

main().catch(err => { console.error(err.message); process.exit(1); });

