import('playwright').then(async ({ chromium }) => {
  const fs = await import('fs');
  const path = await import('path');

  const DATA_DIR = path.join(path.dirname(path.fileURLToPath(import.meta.url)), '..', 'data');
  const CDP_URL = 'http://127.0.0.1:9222';

  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  const talkFrame = page.frames()[1];

  // These are the P0/P1 targets now visible after collapsing pinned
  const targets = [
    'raymond cramotte', 'Doris Akpabio', 'azaan ss', 'amer ly',
    'TheodoraAdelaide Mahe', 'rehema kiseyu', 'Susuanna ParkerAdentwi',
    'Assiatou Barry', 'Krisgel Igros'
  ];

  // Get DOM index map
  const getDOM = async () => talkFrame.evaluate(() => 
    Array.from(document.querySelectorAll('.contact-item-container')).map((el, idx) => {
      const nameEl = el.querySelector('.contact-right');
      const nameText = nameEl ? (nameEl.textContent || '').trim() : '';
      const nameMatch = nameText.match(/^(.+?)(?:\d{2,4}[-:\/])/);
      return { index: idx, name: nameMatch ? nameMatch[1].trim() : nameText.substring(0, 30).trim() };
    })
  );

  const dom = await getDOM();
  const nameToIdx = {};
  dom.forEach(c => { nameToIdx[c.name] = c.index; });

  const results = [];
  for (const name of targets) {
    const idx = nameToIdx[name];
    if (idx === undefined) {
      console.log('SKIP (not in DOM): ' + name);
      continue;
    }

    process.stdout.write('Scraping: ' + name + '...');

    // Click
    await talkFrame.evaluate((i) => {
      const containers = document.querySelectorAll('.contact-item-container');
      if (containers[i]) { containers[i].scrollIntoView({ block: 'center' }); containers[i].click(); }
    }, idx);
    await new Promise(r => setTimeout(r, 1500));

    // Wait for messages
    let has = false;
    for (let i = 0; i < 15; i++) {
      has = await talkFrame.evaluate(() => 
        document.querySelectorAll('.session-rich-content.text, .session-rich-content.card').length > 0
      );
      if (has) break;
      await new Promise(r => setTimeout(r, 500));
    }
    if (!has) { console.log(' NO_MSG'); continue; }

    // Scroll to load full history
    const scrollInfo = await talkFrame.evaluate(() => {
      const sels = ['.message-list-container', '.chat-list', '.im-chat-list', '.message-list',
        '[class*=\"message-list\"]', '[class*=\"chat-list\"]', '.session-message-list-wrapper'];
      for (const sel of sels) {
        const el = document.querySelector(sel);
        if (el && el.scrollHeight > el.clientHeight) return { selector: sel };
      }
      return null;
    });

    if (scrollInfo) {
      let prev = 0, stable = 0;
      for (let i = 0; i < 40; i++) {
        await talkFrame.evaluate((sel) => { const el = document.querySelector(sel); if (el) el.scrollTop = 0; }, scrollInfo.selector);
        await new Promise(r => setTimeout(r, 600));
        const cnt = await talkFrame.evaluate(() => document.querySelectorAll('.message-item-wrapper.messenger').length);
        if (cnt === prev) { stable++; if (stable >= 3) break; }
        else { stable = 0; prev = cnt; }
      }
    }

    // Get messages
    const messages = await talkFrame.evaluate(() => {
      return Array.from(document.querySelectorAll('.message-item-wrapper.messenger'))
        .filter(w => !w.querySelector('.session-security'))
        .map(w => {
          const textEl = w.querySelector('.session-rich-content.text');
          const cardEl = w.querySelector('.session-rich-content.card');
          let content = '';
          if (textEl) content = textEl.textContent.trim()
            .replace(/翻译中…反馈\$/, '').replace(/由阿里翻译提供反馈\$/, '')
            .replace(/阿里国际Marco大模型翻译反馈\$/, '').replace(/由阿里翻译提供\$/, '').trim();
          else if (cardEl) content = cardEl.textContent.trim();
          else return null;
          const timeEl = w.querySelector('p.item-base-info span:last-child');
          return {
            side: w.classList.contains('item-left') ? 'received' : 'sent',
            content: content.substring(0, 2000),
            timestamp: timeEl ? (timeEl.textContent || '').trim() : null,
          };
        }).filter(Boolean);
    });

    console.log(' ' + messages.length + 'msgs');
    results.push({ name, messageCount: messages.length, messages });
  }

  // Load existing merged data and append
  const prevFiles = fs.readdirSync(DATA_DIR).filter(f => f.startsWith('deep_scrape_final_'));
  const prev = prevFiles.length > 0 ? JSON.parse(fs.readFileSync(path.join(DATA_DIR, prevFiles.sort().reverse()[0]), 'utf8')) : { results: [], skipped: [], successCount: 0 };

  const existingNames = new Set(prev.results.map(r => r.name));
  const newResults = results.filter(r => !existingNames.has(r.name));

  const merged = {
    scrapedAt: new Date().toISOString(),
    successCount: prev.successCount + newResults.length,
    results: [...prev.results, ...newResults],
  };

  const dateStr = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
  const outPath = path.join(DATA_DIR, 'deep_scrape_complete_' + dateStr + '.json');
  fs.writeFileSync(outPath, JSON.stringify(merged, null, 2));

  console.log('\\nDone: ' + newResults.length + ' new, total ' + merged.successCount + ' → ' + outPath);
  await browser.close();
});
