      await new Promise(r => setTimeout(r, 600));
      const cnt = await frame.evaluate(() => document.querySelectorAll('.message-item-wrapper.messenger').length);
      if (cnt === prev) { stable++; if (stable >= 3) break; }
      else { stable = 0; prev = cnt; }
    }
  }

