  for (const name of TARGETS) {
    const idx = nameToIdx[name];
    if (idx === undefined) { console.log(`SKIP ${name} - 不在DOM`); continue; }

    process.stdout.write(`${name}...`);
    const msgs = await clickAndScrape(talkFrame, idx);
    results.push({ name, messageCount: msgs.length, messages: msgs });
    console.log(` ${msgs.length}条`);
  }

  // Merge
  const prevFiles = readdirSync(DATA_DIR).filter(f => f.startsWith('deep_scrape_final_'));
  const prev = prevFiles.length > 0
    ? JSON.parse(readFileSync(join(DATA_DIR, prevFiles.sort().reverse()[0]), 'utf8'))
    : { results: [], successCount: 0 };

  const existingNames = new Set(prev.results.map(r => r.name));
  const newResults = results.filter(r => !existingNames.has(r.name));

  const merged = {
    scrapedAt: new Date().toISOString(),
    successCount: prev.successCount + newResults.length,
    results: [...prev.results, ...newResults],
  };

  const dateStr = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
  const outPath = join(DATA_DIR, `deep_scrape_merged_v2_${dateStr}.json`);
  writeFileSync(outPath, JSON.stringify(merged, null, 2));

  console.log(`\n新增: ${newResults.length} | 总计: ${merged.successCount} → ${outPath}`);
  await browser.close();
}

main().catch(err => { console.error(err.message); process.exit(1); });
